```matlab
function independent_expansion(radius, depth, water_density, bubble_density, gravity)
    % 参数解释：
    % radius: 空泡半径
    % depth: 水深
    % water_density: 水的密度
    % bubble_density: 空泡的密度
    % gravity: 重力加速度

    % 计算空泡半径累积高度
    R = linspace(0, radius, 100);
    h = sqrt(radius^2 - R.^2);

    % 计算空泡内部压强与外部压强之差
    delta_p = water_density * gravity * h;

    % 根据独立膨胀原理计算空泡轮廓
    bubble_radius = zeros(size(R));
    bubble_radius(1) = radius;

    for i = 2:length(R)
        bubble_radius(i) = sqrt((bubble_density / (bubble_density - water_density)) * ...
            (bubble_radius(i-1)^2 - (delta_p(i-1) / bubble_density)));
    end

    % 绘制空泡轮廓
    plot(R, bubble_radius);
    xlabel('R');
    ylabel('r');
    title('Bubble Profile');
    grid on;
end

% 示例数据
radius = 0.1;  % 空泡半径，单位：m
depth = 10;  % 水深，单位：m
water_density = 1000;  % 水的密度，单位：kg/m^3
bubble_density = 0.1;  % 空泡的密度，单位：kg/m^3
gravity = 9.8;  % 重力加速度，单位：m/s^2

independent_expansion(radius, depth, water_density, bubble_density, gravity);
```

